// // This module converts a 24-bit digital input to a 24-bit analog output. When the enable signal is low, the output reflects the input value.
module DAC_24bit (
    input wire [23:0] data_in,
    input wire enable,
    output wire [23:0] data_out
);
    assign data_out = enable ? data_in : 24'b0;
endmodule
